import { ErrorMessage, Field, Form, Formik } from "formik";
import moment from "moment";
import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import * as Yup from "yup";
import { clearMessage } from "../../slices/message";

const RequiredMark = () => <span className="tf-required">*</span>;

export const TaskForm = ({ saveTask }) => {
  const clients = useSelector((state) => state.client);
  const { reviewers } = useSelector((state) => state.user);
  const [taskStatus, setTaskStatus] = useState(false);
  const [taskDate, setTaskDate] = useState(moment().format("YYYY-MM-DD"));
  const [reviewerId, setReviewerId] = useState(null);
  const [loading, setLoading] = useState(false);
  const { message } = useSelector((state) => state.message);

  const dispatch = useDispatch();
  useEffect(() => {
    dispatch(clearMessage());
  }, [dispatch]);

  const initialValues = {
    description: "",
    clientId: "",
    minutesSpent: "",
    taskType: "",
    billingCategory: "",
  };

  const validationSchema = Yup.object().shape({
    clientId: Yup.string().required("Client is required"),
    description: Yup.string().required("Description is required"),
    minutesSpent: Yup.number()
      .typeError("Must be a number")
      .positive("Must be positive")
      .required("Time spent is required"),
    taskType: Yup.string().required("Task type is required"),
    billingCategory: Yup.string().required("Billing category is required"),
  });

  const handleSubmit = (formValues) => {
    setLoading(true);
    saveTask({
      ...formValues,
      date: taskDate,
      completed: taskStatus,
      reviewerId: taskStatus ? reviewerId : null,
    })
      .catch((e) => console.error(e))
      .finally(() => setLoading(false));
  };

  return (
    <Formik
      initialValues={initialValues}
      validationSchema={validationSchema}
      onSubmit={handleSubmit}
    >
      {({ errors, touched }) => (
        <Form className="tf-form">
          {message && (
            <div className="alert alert-danger tf-alert" role="alert">
              {message}
            </div>
          )}

          {/* Row 1: Client + Date */}
          <div className="tf-row">
            <div className="tf-field">
              <label htmlFor="clientId">
                Client <RequiredMark />
              </label>
              <Field
                as="select"
                name="clientId"
                id="clientId"
                className={`form-control ${errors.clientId && touched.clientId ? "is-invalid" : ""}`}
              >
                <option value="">-- Select Client --</option>
                {clients?.map((c) => (
                  <option key={c.id} value={c.id}>
                    {c.name}
                  </option>
                ))}
              </Field>
              <ErrorMessage
                name="clientId"
                component="div"
                className="tf-error"
              />
            </div>

            <div className="tf-field">
              <label htmlFor="taskDate">
                Date <RequiredMark />
              </label>
              <input
                type="date"
                id="taskDate"
                className="form-control"
                value={taskDate}
                onChange={(e) => setTaskDate(e.target.value)}
              />
            </div>
          </div>

          {/* Row 2: Task Type + Billing Category */}
          <div className="tf-row">
            <div className="tf-field">
              <label htmlFor="taskType">
                Task Type <RequiredMark />
              </label>
              <Field
                as="select"
                name="taskType"
                id="taskType"
                className={`form-control ${errors.taskType && touched.taskType ? "is-invalid" : ""}`}
              >
                <option value="">-- Select Type --</option>
                <option value="Income Tax">Income Tax</option>
                <option value="GST">GST</option>
                <option value="MCA">MCA</option>
                <option value="FEMA">FEMA</option>
                <option value="DGFT">DGFT</option>
                <option value="Others">Others</option>
              </Field>
              <ErrorMessage
                name="taskType"
                component="div"
                className="tf-error"
              />
            </div>

            <div className="tf-field">
              <label htmlFor="billingCategory">
                Billing Category <RequiredMark />
              </label>
              <Field
                as="select"
                name="billingCategory"
                id="billingCategory"
                className={`form-control ${errors.billingCategory && touched.billingCategory ? "is-invalid" : ""}`}
              >
                <option value="">-- Select Category --</option>
                <option value="Billable">Billable</option>
                <option value="Non-Billable">Non-Billable</option>
                <option value="Retainer">Retainer</option>
              </Field>
              <ErrorMessage
                name="billingCategory"
                component="div"
                className="tf-error"
              />
            </div>
          </div>

          {/* Row 3: Description (full width) */}
          <div className="tf-row tf-row-full">
            <div className="tf-field">
              <label htmlFor="description">
                Description <RequiredMark />
              </label>
              <Field
                as="textarea"
                name="description"
                id="description"
                rows="3"
                placeholder="What did you work on?"
                className={`form-control ${errors.description && touched.description ? "is-invalid" : ""}`}
              />
              <ErrorMessage
                name="description"
                component="div"
                className="tf-error"
              />
            </div>
          </div>

          {/* Row 4: Time Spent + Status */}
          <div className="tf-row">
            <div className="tf-field">
              <label htmlFor="minutesSpent">
                Time Spent (minutes) <RequiredMark />
              </label>
              <Field
                type="number"
                name="minutesSpent"
                id="minutesSpent"
                min="1"
                placeholder="e.g. 60"
                className={`form-control ${errors.minutesSpent && touched.minutesSpent ? "is-invalid" : ""}`}
              />
              <ErrorMessage
                name="minutesSpent"
                component="div"
                className="tf-error"
              />
            </div>

            <div className="tf-field">
              <label>
                Status <RequiredMark />
              </label>
              <div className="tf-status-toggle">
                <button
                  type="button"
                  className={`tf-status-btn ${taskStatus ? "" : "active in-progress"}`}
                  onClick={() => setTaskStatus(false)}
                >
                  In-Progress
                </button>
                <button
                  type="button"
                  className={`tf-status-btn ${taskStatus ? "active completed" : ""}`}
                  onClick={() => setTaskStatus(true)}
                >
                  Completed
                </button>
              </div>
            </div>
          </div>

          {/* Reviewer (conditional) */}
          {taskStatus && (
            <div className="tf-row tf-row-full tf-slide-in">
              <div className="tf-field">
                <label htmlFor="reviewerId">
                  Reviewed By <small className="text-muted">(optional)</small>
                </label>
                <select
                  id="reviewerId"
                  className="form-control"
                  value={reviewerId || ""}
                  onChange={(e) => setReviewerId(e.target.value || null)}
                >
                  <option value="">-- Select Reviewer --</option>
                  {reviewers?.map((r) => (
                    <option key={r.id} value={r.id}>
                      {r.username}
                    </option>
                  ))}
                </select>
              </div>
            </div>
          )}

          {/* Submit */}
          <div className="tf-submit-row">
            <button
              type="submit"
              className="btn btn-primary tf-submit-btn"
              disabled={loading}
            >
              {loading ? (
                <>
                  <span className="spinner-border spinner-border-sm mr-2" />{" "}
                  Saving...
                </>
              ) : (
                "Submit Task"
              )}
            </button>
          </div>
        </Form>
      )}
    </Formik>
  );
};
